package com.infy.inventrack.catalog.mapper; import com.infy.inventrack.catalog.entity.*; import com.infy.inventrack.common.dto.*; public final class CatalogMapper { private CatalogMapper(){} public static ProductResponse toProductResponse(Product p){ return new ProductResponse(p.getProductId(),p.getProductName(),p.getSku(),p.getPrice(),p.getImageUrl(),p.getCategory().getName(),p.getDescription(),p.getBrand(),p.getStockQuantity()); } public static CategoryResponse toCategoryResponse(Category c){ return new CategoryResponse(c.getId(),c.getName()); } }
